import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Dashboard.css";

function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const [filter, setFilter] = useState("recent");
  const [category, setCategory] = useState("all");

  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user") || "null");

  // ✅ Fetch questions
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data))
      .catch((err) => console.error(err));
  }, []);

  // ✅ Logout
  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  // ✅ Filter logic
  const filtered = questions
    .filter((q) => {
      if (category === "all") return true;
      return q.category === category;
    })
    .sort((a, b) => {
      if (filter === "recent") {
        return new Date(b.createdAt) - new Date(a.createdAt);
      }

      if (filter === "popular") {
        return b.views - a.views; // ✅ MOST VIEWED FIRST
      }

      return 0;
    });
  return (
    <div className="container">

      {/* NAVBAR */}
      <div className="navbar">
        <div className="left">
          <div className="logo">C</div>
          <div>
            <h3>Campus Connect</h3>
            <span>Student Learning Hub</span>
          </div>
        </div>

        <div className="right">
          <div className="profile">
            <div className="avatar">{user?.name?.[0]}</div>
            <div>
              <p>{user?.name}</p>
              <span>{user?.role}</span>
            </div>
          </div>

          <button onClick={handleLogout}>Logout</button>
        </div>
      </div>

      {/* BODY */}
      <div className="content">

        {/* SIDEBAR */}
        <div className="sidebar">
          <h4>Filters</h4>

          <button
            className={filter === "recent" ? "active" : ""}
            onClick={() => setFilter("recent")}
          >
            Recent
          </button>

          <button
            className={filter === "popular" ? "active" : ""}
            onClick={() => setFilter("popular")}
          >
            Popular
          </button>

          <h5>Category</h5>

          <button
            className={category === "all" ? "active" : ""}
            onClick={() => setCategory("all")}
          >
            All Posts
          </button>

          <button
            className={category === "notes" ? "active" : ""}
            onClick={() => setCategory("notes")}
          >
            Study Notes
          </button>

          <button
            className={category === "projects" ? "active" : ""}
            onClick={() => setCategory("projects")}
          >
            Projects
          </button>

          <button
            className={category === "guidance" ? "active" : ""}
            onClick={() => setCategory("guidance")}
          >
            Guidance
          </button>

          <button
            className={category === "career" ? "active" : ""}
            onClick={() => setCategory("career")}
          >
            Career
          </button>

          <button
            className={category === "skills" ? "active" : ""}
            onClick={() => setCategory("skills")}
          >
            Skills
          </button>
        </div>

        {/* MAIN */}
        <div className="main">

          <div className="header">
            <div>
              <h2>All Posts</h2>
              <p>{filtered.length} posts available</p>
            </div>

            <Link to="/ask" className="new-post">
              + New Post
            </Link>
          </div>

          {/* POSTS */}
          {filtered.map((q) => (
            <div key={q._id} className="post">

              {/* TOP */}
              <div className="post-top">
                <div className="user">

                  {/* ✅ FIXED AVATAR */}
                  <div className="avatar small">
                    {q.postedBy?.[0]}
                  </div>

                  <div>
                    <b>{q.postedBy}</b>
                    <span>{q.role}</span>
                  </div>
                </div>

                <span className="tag">{q.category}</span>
              </div>

              {/* CONTENT */}
              <h3>{q.title}</h3>
              <p>{q.description}</p>

              {/* ✅ FILE DISPLAY */}
{q.file && (
  <a
    href={`http://localhost:5000/uploads/${q.file}`}
    target="_blank"
    rel="noreferrer"
    style={{ display: "block", marginTop: "10px", color: "#4a6cf7" }}
  >
    📎 View Attachment
  </a>
)}
              {/* BOTTOM */}
              <div className="post-bottom">
                <span>👁 {q.views || 0}</span>   {/* ✅ ADD THIS */}

                <span>❤️ 0</span>
                <span>💬 {q.answer ? 1 : 0}</span>

                <Link to={`/answers/${q._id}`} className="view-btn">
                  View →
                </Link>
              </div>

            </div>
          ))}

        </div>
      </div>
    </div>
  );
}

export default Dashboard;
